    StateDigest, Testimony,
};
use signal_spirit_judge::{
    AdmissionJudgeOperation, AdmissionJudgePacket, JudgmentScope, SpiritJudgeReply,
    SpiritJudgeRequest,
};

#[tokio::main]
async fn main() {
    let socket = std::env::args().nth(1).expect("socket path is required");
    let request = SpiritJudgeRequest::JudgeAdmission(AdmissionJudgePacket::new(
        JudgmentScope::public(),
        AdmissionJudgeOperation::Record(RecordRequest {
            entry: Entry {
                domains: Domains::new(Vec::new()),
                kind: Kind::Principle,
                description: Description::new("Provider compatibility witness."),
                certainty: Certainty::new(Magnitude::High),
                importance: Importance::new(Magnitude::Medium),
                privacy: Privacy::new(Magnitude::Zero),
                referents: Referents::new(Vec::new()),
