            justification: Justification {
                testimony: Testimony::new(Vec::new()),
                reasoning: Reasoning::new("isolated provider witness"),
            },
        }),
        RecordSet::new(Vec::new()),
        DatabaseMarker {
            commit_sequence: CommitSequence::new(0),
            state_digest: StateDigest::new(0),
        },
    ));
    let reply = SpiritJudgeClient::new(SpiritJudgeSocketPath::new(socket))
        .submit(request)
        .await
        .expect("judge socket exchange");
    let class = match reply {
        SpiritJudgeReply::AdmissionJudged(_) => "admission-judged",
        SpiritJudgeReply::ReferentRegistrationJudged(_) => "referent-registration-judged",
        SpiritJudgeReply::RequestRejected(_) => "request-rejected",
    };
    println!("{class}");
}
